const body = $input.item.json.body || {};
const url = (body.url || '').trim();
if (!url || !url.startsWith('http')) $execution.abort({ message: 'Invalid URL' });
return [{ json: { url } }];

const html = String($input.item.json || '');
const storeUrl = $('Validate').item.json.url;
// Strip HTML tags to get readable text, limit to 3000 chars
const text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 3000);
const prompt = `Analyse this e-commerce store and return a JSON object with exactly these keys:\n{
  "summary": "1-2 sentence brand/product summary",
  "target_audience": "1-2 sentence description of ideal customer",
  "products": ["product1", "product2", "product3"],
  "ad_opportunities": "2-3 specific Meta ad angles that would work well",
  "meta_strategy": "Recommended Meta Ads strategy: campaign objective, audience targeting approach, and creative angle"
}\n\nStore URL: ${storeUrl}\nStore page content (truncated):\n${text}\n\nReturn ONLY valid JSON, no markdown, no explanation.`;
return [{ json: { prompt } }];

const result = $input.item.json;
const text = (result.content?.[0]?.text || '{}').trim();
let parsed;
try {
  parsed = JSON.parse(text);
} catch(e) {
  const match = text.match(/\{[\s\S]*\}/);
  try { parsed = JSON.parse(match?.[0] || '{}'); } catch(e2) { parsed = {}; }
}
return [{
  json: {
    summary: parsed.summary || 'Could not analyse store.',
    target_audience: parsed.target_audience || '—',
    products: Array.isArray(parsed.products) ? parsed.products : [],
    ad_opportunities: parsed.ad_opportunities || '—',
    meta_strategy: parsed.meta_strategy || '—'
  }
}];
